const refresh = crypto.randomBytes(32).toString('hex');
await redis.set(`rt:${refresh}`, user.id, 'EX', 7*24*60*60);
``` |
| **Autorisation (RBAC)** | Middleware qui vérifie `req.user.role` et compare à une liste d’actions autorisées par rôle (admin, restaurateur, livreur, client). | Empêche qu’un client modifie le menu d’un restaurant. | ```js
const permit = (...allowed) => (req,res,next)=>{
  if (allowed.includes(req.user.role)) return next();
  res.status(403).json({error:'Forbidden'});
};
